(function (global) {
  'use strict';

  function clamp(v, min, max) { return Math.max(min, Math.min(max, v)); }

  function Vector2(x, y) { this.x = x || 0; this.y = y || 0; }
  Vector2.prototype.clone = function () { return new Vector2(this.x, this.y); };
  Vector2.prototype.add = function (v) { this.x += v.x; this.y += v.y; return this; };
  Vector2.prototype.copy = function (v) { this.x = v.x; this.y = v.y; return this; };

  function Vector3(x, y, z) { this.x = x || 0; this.y = y || 0; this.z = z || 0; }
  Vector3.prototype.set = function (x, y, z) { this.x = x; this.y = y; this.z = z; return this; };
  Vector3.prototype.copy = function (v) { this.x = v.x; this.y = v.y; this.z = v.z; return this; };
  Vector3.prototype.clone = function () { return new Vector3(this.x, this.y, this.z); };
  Vector3.prototype.sub = function (v) { this.x -= v.x; this.y -= v.y; this.z -= v.z; return this; };

  function Color(hex) { this.hex = hex || '#000000'; }
  function Fog(color, near, far) { this.color = color; this.near = near; this.far = far; }

  function Object3D() {
    this.position = new Vector3();
    this.rotation = new Vector3();
    this.children = [];
    this.castShadow = false;
    this.receiveShadow = false;
  }

  function Scene() { Object3D.call(this); this.background = null; this.fog = null; this.objects = []; }
  Scene.prototype = Object.create(Object3D.prototype);
  Scene.prototype.add = function () { for (var i = 0; i < arguments.length; i++) { this.objects.push(arguments[i]); } };
  Scene.prototype.remove = function (obj) { this.objects = this.objects.filter(function (o) { return o !== obj; }); };

  function PerspectiveCamera(fov, aspect, near, far) {
    Object3D.call(this);
    this.fov = fov; this.aspect = aspect; this.near = near; this.far = far;
    this.target = new Vector3();
  }
  PerspectiveCamera.prototype = Object.create(Object3D.prototype);
  PerspectiveCamera.prototype.lookAt = function (v) { this.target.copy(v); };
  PerspectiveCamera.prototype.updateProjectionMatrix = function () {};

  function Mesh(geometry, material) { Object3D.call(this); this.geometry = geometry; this.material = material; }
  Mesh.prototype = Object.create(Object3D.prototype);

  function Light(color, intensity) { Object3D.call(this); this.color = color; this.intensity = intensity || 1; }
  Light.prototype = Object.create(Object3D.prototype);
  function AmbientLight(c, i) { Light.call(this, c, i); }
  AmbientLight.prototype = Object.create(Light.prototype);
  function HemisphereLight(c, g, i) { Light.call(this, c, i); this.groundColor = g; }
  HemisphereLight.prototype = Object.create(Light.prototype);
  function DirectionalLight(c, i) {
    Light.call(this, c, i);
    this.shadow = { mapSize: { set: function () {} } };
  }
  DirectionalLight.prototype = Object.create(Light.prototype);
  function PointLight(c, i, d, de) { Light.call(this, c, i); this.distance = d; this.decay = de; }
  PointLight.prototype = Object.create(Light.prototype);

  function PlaneGeometry(w, h) { this.type = 'plane'; this.w = w; this.h = h; }
  function BoxGeometry(w, h, d) { this.type = 'box'; this.w = w; this.h = h; this.d = d; }
  function IcosahedronGeometry(r) { this.type = 'ico'; this.r = r; }
  function GridHelper(size, divisions) { Object3D.call(this); this.type = 'grid'; this.size = size; this.divisions = divisions; }
  GridHelper.prototype = Object.create(Object3D.prototype);

  function MeshStandardMaterial(opts) {
    opts = opts || {};
    this.color = opts.color || '#ffffff';
    this.emissive = opts.emissive || '#000000';
    this.emissiveIntensity = opts.emissiveIntensity || 0;
    this.transparent = !!opts.transparent;
    this.opacity = opts.opacity == null ? 1 : opts.opacity;
  }

  function Clock() { this._last = Date.now(); }
  Clock.prototype.getDelta = function () { var n = Date.now(), d = (n - this._last) / 1000; this._last = n; return d; };

  function worldToScreen(v, camera, w, h) {
    var forward = camera.target.clone().sub(camera.position);
    var fl = Math.hypot(forward.x, forward.y, forward.z) || 1;
    forward.x /= fl; forward.y /= fl; forward.z /= fl;

    var up = new Vector3(0, 1, 0);
    var right = new Vector3(
      up.y * forward.z - up.z * forward.y,
      up.z * forward.x - up.x * forward.z,
      up.x * forward.y - up.y * forward.x
    );
    var rl = Math.hypot(right.x, right.y, right.z) || 1;
    right.x /= rl; right.y /= rl; right.z /= rl;

    up = new Vector3(
      forward.y * right.z - forward.z * right.y,
      forward.z * right.x - forward.x * right.z,
      forward.x * right.y - forward.y * right.x
    );

    var rel = v.clone().sub(camera.position);
    var cx = rel.x * right.x + rel.y * right.y + rel.z * right.z;
    var cy = rel.x * up.x + rel.y * up.y + rel.z * up.z;
    var cz = rel.x * forward.x + rel.y * forward.y + rel.z * forward.z;
    if (cz <= 0.1) return null;
    var f = 1 / Math.tan((camera.fov * Math.PI / 180) / 2);
    var nx = (cx * f / camera.aspect) / cz;
    var ny = (cy * f) / cz;
    return { x: (nx * 0.5 + 0.5) * w, y: (1 - (ny * 0.5 + 0.5)) * h, z: cz };
  }

  function WebGLRenderer(opts) {
    opts = opts || {};
    this.domElement = opts.canvas || document.createElement('canvas');
    this.ctx = this.domElement.getContext('2d');
    this.shadowMap = { enabled: false };
    this.outputColorSpace = '';
  }
  WebGLRenderer.prototype.setPixelRatio = function () {};
  WebGLRenderer.prototype.setSize = function (w, h) { this.domElement.width = w; this.domElement.height = h; };
  WebGLRenderer.prototype.render = function (scene, camera) {
    var ctx = this.ctx;
    if (!ctx) return;
    var w = this.domElement.width, h = this.domElement.height;
    ctx.fillStyle = scene.background && scene.background.hex ? scene.background.hex : '#020617';
    ctx.fillRect(0, 0, w, h);

    // floor grid (pseudo 3D)
    ctx.strokeStyle = '#1e293b';
    for (var gx = -9; gx <= 9; gx++) {
      var a = worldToScreen(new Vector3(gx + 0.5, 0, -9), camera, w, h);
      var b = worldToScreen(new Vector3(gx + 0.5, 0, 9), camera, w, h);
      if (a && b) { ctx.beginPath(); ctx.moveTo(a.x, a.y); ctx.lineTo(b.x, b.y); ctx.stroke(); }
    }
    for (var gz = -9; gz <= 9; gz++) {
      var c = worldToScreen(new Vector3(-9, 0, gz + 0.5), camera, w, h);
      var d = worldToScreen(new Vector3(9, 0, gz + 0.5), camera, w, h);
      if (c && d) { ctx.beginPath(); ctx.moveTo(c.x, c.y); ctx.lineTo(d.x, d.y); ctx.stroke(); }
    }

    var drawables = [];
    (scene.objects || []).forEach(function (obj) {
      if (!(obj instanceof Mesh)) return;
      var p = worldToScreen(obj.position, camera, w, h);
      if (!p) return;
      drawables.push({ p: p, obj: obj });
    });
    drawables.sort(function (a, b) { return b.p.z - a.p.z; });

    drawables.forEach(function (entry) {
      var obj = entry.obj, p = entry.p;
      var size = clamp(320 / (p.z + 1), 6, 70);
      var color = (obj.material && obj.material.color) || '#ffffff';
      if (obj.geometry && obj.geometry.type === 'ico') {
        ctx.fillStyle = color;
        ctx.beginPath();
        ctx.arc(p.x, p.y, size * 0.45, 0, Math.PI * 2);
        ctx.fill();
      } else {
        ctx.fillStyle = color;
        ctx.fillRect(p.x - size * 0.45, p.y - size * 0.45, size * 0.9, size * 0.9);
      }
    });
  };

  var THREE = {
    Scene: Scene,
    Color: Color,
    Fog: Fog,
    PerspectiveCamera: PerspectiveCamera,
    WebGLRenderer: WebGLRenderer,
    Vector2: Vector2,
    Vector3: Vector3,
    AmbientLight: AmbientLight,
    HemisphereLight: HemisphereLight,
    DirectionalLight: DirectionalLight,
    PointLight: PointLight,
    Mesh: Mesh,
    PlaneGeometry: PlaneGeometry,
    BoxGeometry: BoxGeometry,
    IcosahedronGeometry: IcosahedronGeometry,
    MeshStandardMaterial: MeshStandardMaterial,
    GridHelper: GridHelper,
    Clock: Clock,
    SRGBColorSpace: 'srgb'
  };

  global.THREE = THREE;
})(window);
